VALUES
  ('real-estate-moex-01642', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '甲向乙建設公司購買預售屋，並簽訂定型化契約，該契約中有「屋簷面積計入買賣價格」之定型化契約 條款。請問該預售屋買賣定型化契約效力為何？', '["無效，因為違反預售屋買賣定型化契約應記載及不得記載事項", "無效，因為顯失公平", "有效，因為甲已同意該契約所有條款", "有效，因為以一部無效為原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01643', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依消費者保護法規定，消費爭議調解辦法由何機關定之？', '["消費者爭議調解委員會", "消費者保護委員會", "消費者服務中心", "各直轄市或縣（市）政府"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01644', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依消費者保護法規定，下列有關企業經營者之敘述何者正確？', '["企業經營者對消費者或第三人之損害賠償責任，經與消費者個別磋商，得預先約定限制或免除", "輸入商品或服務之企業經營者，視為從事經銷之企業經營者", "從事經銷之企業經營者，就商品所生之損害，與商品製造者連帶負賠償責任。但對於損害之防免已盡 相當之注意，或縱加以相當之注意而仍不免發生損害者，不在此限", "從事設計、生產、製造商品或提供服務之企業經營者，違反消費者保護法規定致生損害於消費者，若 企業經營者能證明其無過失者，法院得免除其賠償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01645', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '甲消費者保護團體依消費者保護法第四十九條規定提起訴訟。下列敘述何者正確？', '["應經消費者保護基金會的同意，始得提起該訴訟", "如已置有消費者保護專門人員，則可不委任律師代理訴訟", "如委任律師代理訴訟，該律師不得請求預付必要費用", "固然甲並非被害人，但甲仍得為該訴訟的原告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01646', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '因同一消費關係而被害之甲、乙、丙，依民事訴訟法之規定，選定甲與乙起訴請求損害賠償。以下敘述 何者正確？', '["此為法定訴訟擔當", "甲與乙稱為選定人", "甲與乙稱為選定當事人", "該訴訟繫屬中，同一消費關係之其他被害人丁與戊在法院判決前，均得併案請求賠償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01647', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '消費者甲向企業經營者乙提起消費訴訟，下列敘述何者正確？', '["法院為甲敗訴之判決時，得依職權宣告為減少擔保之假執行。果爾，乙得在判決確定前，聲請法院強 制執行甲的財產", "法院為乙敗訴之判決時，得依職權宣告為免除擔保之假處分", "法院為乙敗訴之判決時，得依職權宣告為減少擔保之假扣押", "法院為乙敗訴之判決時，得依職權宣告為免除擔保之假執行。果爾，甲得在判決確定前，聲請法院強 制執行乙的財產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01648', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '甲慈善事業的慈善經營方式是：以一般價格購買商品後，將其便宜賣給貧困者。貧困者乙向甲便宜購買 商品，如因而受有身體上的損害，請問乙主張甲就此應負商品責任，有無理由？', '["有理由，因為甲應負不完全給付的商品責任", "有理由，因為甲反覆為此行為並以此為業", "無理由，因為甲的行為並非以營利為目的", "無理由，因為人身損害並非商品責任所規範"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01649', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '設若消費者保護基金會對於同一之原因事件，致使眾多消費者受害時，受讓甲、乙、丙等20位消費者損 害賠償請求權後，以自己名義，提起消費訴訟。以下敘述何者正確？', '["如甲僅有非財產上損害賠償請求權，因該權利具一身專屬性，故不得讓與給消費者保護基金會", "該訴訟繫屬中，如乙終止讓與損害賠償請求權，消費者保護基金會仍具當事人適格", "在該訴訟判決前，丙均得終止讓與損害賠償請求權，並通知法院", "消費者保護基金會應將該訴訟結果所得賠償，交付甲、乙、丙等20位消費者，不得扣除訴訟費用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01650', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依消費者保護法規定，下列有關調解之敘述何者正確？', '["消費爭議調解委員會，由委員互推主席", "依消費者保護法第四十五條之二，有關一般消費爭議經委員會依職權調解提出之解決方案，應經全體 調解委員過半數之同意", "當事人對委員會依職權調解之方案，得於送達後十五日之不變期間內，提出異議", "調解成立者應作成調解書。調解書之作成及效力，準用鄉鎮市調解條例第二十二條至第二十六條之規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01651', 'real-estate', 'real-estate-moex-103-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依消費者保護法規定，下列有關分期付款買賣契約書之敘述何者錯誤？', '["分期付款買賣契約應以書面為之", "分期付款買賣之附加費用，應明確記載併入各期價款計算之利息數額", "契約書未記載利率者，其利率按現金交易價格週年利率百分之五計算之", "契約書未載明頭期款、各期價款與其他附加費用合計之總價款與現金交易之差額者，消費者不負現金 交易價格以外價款之給付義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "465a45c6b93e", "answer_pdf_sha1": "c43a5bb3af14", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
